use std::error::Error;

struct SensorData {
    readings: Vec<f64>,
}

impl SensorData {
    fn new(readings: Vec<f64>) -> Self {
        SensorData { readings }
    }

    fn calculate_mean(&self) -> Result<f64, Box<dyn Error>> {
        let count = self.readings.len();
        if count == 0 {
            return Err(Box::new(std::io::Error::new(std::io::ErrorKind::InvalidData, "No readings found")));
        }

        let sum: f64 = self.readings.iter().sum();
        Ok(sum / (count as f64))
    }
}

use std::collections::HashMap;

struct User {
    id: u32,
    username: String,
    is_admin: bool,
}

fn get_api_response_data(users: Vec<User>, required_role_id: u32) -> HashMap<u32, String> {
    let initial_iter = users.into_iter();

    let processed_iter = initial_iter
        .filter(|user| user.is_admin && user.id != required_role_id)
        .map(|user| (user.id, format!("User {} accessed", user.username)));

    processed_iter.collect()
}

fn main() {
    let users = vec![ 
        User { id: 101, username: String::from("Alice"), is_admin: true },
        User { id: 202, username: String::from("Bob"), is_admin: false },
        User { id: 303, username: String::from("Charlie"), is_admin: true },
    ];
    let role_to_exclude = 101;

    let mut response_map = HashMap::new();
    response_map.insert(999, String::from("API Initialized"));

    let final_data = get_api_response_data(users, role_to_exclude);

    for (id, data) in final_data {
        println!("Processing ID {}: {}", id, data);
        response_map.insert(id, data);
    }

    println!("Final response map size: {}", response_map.len());
}

use std::fs::File;
use std::io::{self, BufReader, BufRead};

struct LogEntry {
    timestamp: String,
    level: String,
    message: String,
}

fn parse_line(line: &str) -> Option<LogEntry> {
    let parts: Vec<&str> = line.split("|").collect();
    if parts.len() >= 3 {
        Some(LogEntry {
            timestamp: parts[0].to_string(),
            level: parts[1].to_string(),
            message: parts[2].to_string(),
        })
    } else {
        None
    }
}

fn process_log_stream(file_paths: &[&str]) -> io::Result<Vec<LogEntry>> {
    let mut results = Vec::new();
    for path in file_paths {
        let file = File::open(path).expect("Failed to open log file:");
        let reader = BufReader::new(file);
        for line_result in reader.lines() {
            match line_result {
                Ok(line) => {
                    if let Some(entry) = parse_line(&line) {
                        results.push(entry)
                    }
                },
                Err(e) => {
                    println!("Error reading line from {}: {}", path, e);
                }
            }
        }
    }
    Ok(results)
}

use std::collections::VecDeque;

struct GameState {
    board: Vec<Vec<char>>,
    active_pieces: VecDeque<String>,
}

impl GameState {
    fn new() -> Self {
        GameState {
            board: vec![vec!['.'; 10]; 20],
            active_pieces: VecDeque::new(),
        }
    }

    fn process_data(input_values: &[i32]) -> i32 {
        let filtered = input_values.iter().copied().filter(|&x| x > 5);
        let mapped = filtered.map(|x| x * 2 - 10);
        let final_iterator = mapped.collect::<Vec<i32>>();

        if final_iterator.is_empty() {
            return -1;
        }

        final_iterator.iter().find(|&&val| val == 40).copied().unwrap_or(-99)
    }
}

fn main() {
    let raw_inputs = vec![2, 8, 3, 12, 7, 1];
    let result = GameState::process_data(&raw_inputs);
    println!("The final processed value was: {}", result);
}

use std::fs::File;
use std::io::{self, BufReader, BufRead};

fn main() -> io::Result<()> {
    let file = File::open("log_data.txt")?;
    let reader = BufReader::new(file);

    let mut lines = Vec::new();
    for line in reader.lines() {
        lines.push(line?);
    }

    let valid_pairs: Vec<String> = lines
        .into_iter()
        .filter(|line| !line.is_empty() && line.contains(':'))
        .map(|line| line.trim().to_string()) 
        .collect();

    let sorted_pairs: Vec<String> = {
        let mut temp_vec = valid_pairs;
        temp_vec.sort();
        temp_vec
    };

    for pair in sorted_pairs {
        println!("Processed item: {}", pair);
    }

    Ok(())
}
